/* === Template 12 Portal Form === */
.portal-form-wrapper { display: flex; flex-direction: column; gap: 16px; }
.portal-row { display: flex; gap: 16px; }
.portal-row > .portal-half { flex: 1; min-width: 0; }
.portal-full { width: 100%; }
.portal-field input,
.portal-field select {
  width: 100%;
  height: 48px;
  padding: 0 12px;
  font-size: 16px;
  line-height: 48px;
  border: 1px solid #8c8c8c;
  border-radius: 4px;
  box-sizing: border-box;
  font-family: Delivery, Verdana, sans-serif;
  color: #333;
  background: #fff;
  outline: none;
  transition: border-color 0.15s;
}
.portal-field input:focus,
.portal-field select:focus {
  border-color: #0056a2;
  border-width: 2px;
}
.portal-field input::placeholder {
  color: #8c8c8c;
  font-size: 16px;
  opacity: 1;
}
.portal-field select {
  appearance: auto;
  -webkit-appearance: auto;
  cursor: pointer;
}
.portal-field select:invalid {
  color: #8c8c8c;
}
.portal-field select option {
  color: #333;
}
.portal-field select option:disabled {
  color: #8c8c8c;
}

/* === 3-Step Indicator Fixes === */
.sc-a0d4f61e-0.jleSta { gap: 40px; }
.sc-a0d4f61e-3.hxWmwJ,
.sc-a0d4f61e-3.hNXTrP { width: 110px; font-size: 13px; }
.sc-a0d4f61e-4.cVyzyX { width: 80px; left: 60px; }
/* Done step (checkmark, green bg) */
.step-done { background-color: #4caf50 !important; border: none !important; color: #fff !important; }

/* === Portal Step Indicator === */
.sc-a0d4f61e-0 { display: none !important; }
.portal-steps {
  display: flex;
  align-items: flex-start;
  justify-content: center;
  width: 100%;
  margin: 0 auto 28px;
  padding: 0 10px;
  box-sizing: border-box;
}
.portal-step {
  display: flex;
  flex-direction: column;
  align-items: center;
  flex-shrink: 0;
  min-width: 90px;
  opacity: 0;
  transform: translateY(8px);
  animation: stepFadeIn 0.5s ease forwards;
}
.portal-step:nth-child(1) { animation-delay: 0.1s; }
.portal-step:nth-child(3) { animation-delay: 0.3s; }
.portal-step:nth-child(5) { animation-delay: 0.5s; }
@keyframes stepFadeIn {
  to { opacity: 1; transform: translateY(0); }
}

/* Circle */
.portal-step-circle {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 15px;
  font-weight: 700;
  transition: all 0.3s ease;
  flex-shrink: 0;
}
.portal-step-circle.active {
  background: #333;
  color: #fff;
  box-shadow: 0 0 0 4px rgba(51, 51, 51, 0.15);
}
.portal-step-circle.done {
  background: #4caf50;
  color: #fff;
}
.portal-step-circle.upcoming {
  background: #fff;
  color: #999;
  border: 2px solid #ddd;
}

/* Label */
.portal-step-label {
  font-size: 12px;
  font-weight: 600;
  color: #555;
  text-align: center;
  margin-top: 8px;
  line-height: 1.3;
  max-width: 110px;
  font-family: Delivery, Verdana, sans-serif;
}
.portal-step.active .portal-step-label { color: #333; font-weight: 700; }
.portal-step.done .portal-step-label { color: #4caf50; }
.portal-step.upcoming .portal-step-label { color: #bbb; }

/* Connector line */
.portal-step-line {
  flex: 1;
  height: 3px;
  min-width: 40px;
  max-width: 80px;
  background: #e5e5e5;
  margin-top: 19px;
  border-radius: 2px;
  opacity: 0;
  animation: lineFadeIn 0.4s ease forwards;
  position: relative;
  overflow: hidden;
}
.portal-step-line:nth-child(2) { animation-delay: 0.2s; }
.portal-step-line:nth-child(4) { animation-delay: 0.4s; }
@keyframes lineFadeIn {
  to { opacity: 1; }
}
.portal-step-line.done {
  background: #4caf50;
}
.portal-step-line.done::after {
  content: '';
  position: absolute;
  top: 0; left: 0; bottom: 0;
  width: 100%;
  background: #4caf50;
  animation: lineGrow 0.6s ease forwards;
  animation-delay: 0.3s;
  transform-origin: left;
  transform: scaleX(0);
}
@keyframes lineGrow {
  to { transform: scaleX(1); }
}

/* === OTP Page === */
.otp-container {
  text-align: center;
  padding: 30px 20px 40px;
  font-family: Delivery, Verdana, sans-serif;
}
.otp-icon {
  margin-bottom: 20px;
}
.otp-icon svg {
  animation: phoneShake 2s ease-in-out infinite;
}
@keyframes phoneShake {
  0%, 100% { transform: rotate(0deg); }
  10% { transform: rotate(-8deg); }
  20% { transform: rotate(8deg); }
  30% { transform: rotate(-5deg); }
  40% { transform: rotate(5deg); }
  50%, 100% { transform: rotate(0deg); }
}
.otp-title {
  font-size: 22px;
  font-weight: 700;
  color: #333;
  margin: 0 0 8px;
}
.otp-sub {
  font-size: 14px;
  color: #888;
  margin: 0 0 8px;
  line-height: 1.5;
}
.otp-phone {
  font-size: 15px;
  font-weight: 700;
  color: #333;
  margin: 0 0 30px;
  letter-spacing: 1px;
}

/* OTP Input */
.otp-field-wrap {
  max-width: 280px;
  margin: 0 auto 24px;
}
.otp-input {
  width: 100%;
  height: 56px;
  font-size: 28px;
  font-weight: 700;
  text-align: center;
  letter-spacing: 12px;
  padding: 0 16px;
  border: 2px solid #d1d5db;
  border-radius: 10px;
  box-sizing: border-box;
  font-family: 'Courier New', monospace;
  color: #111;
  background: #fff;
  outline: none;
  transition: border-color 0.2s ease, box-shadow 0.2s ease;
}
.otp-input:focus {
  border-color: #d40511;
  box-shadow: 0 0 0 3px rgba(212, 5, 17, 0.1);
}
.otp-input::placeholder {
  color: #d1d5db;
  letter-spacing: 8px;
  font-size: 22px;
}

/* Timer */
.otp-timer {
  font-size: 13px;
  color: #999;
  margin-bottom: 24px;
}
.otp-timer strong {
  color: #d40511;
  font-weight: 700;
}

/* Verify Button */
.otp-verify-btn {
  display: block;
  width: 100%;
  max-width: 280px;
  margin: 0 auto 16px;
  padding: 14px;
  background: #d40511;
  color: #fff;
  font-size: 16px;
  font-weight: 700;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  font-family: Delivery, Verdana, sans-serif;
  transition: background 0.2s, transform 0.1s;
}
.otp-verify-btn:hover {
  background: #b00410;
  transform: translateY(-1px);
}
.otp-verify-btn:active {
  transform: translateY(0);
}
.otp-verify-btn:disabled {
  background: #ccc;
  cursor: not-allowed;
  transform: none;
}

/* Resend */
.otp-resend {
  font-size: 13px;
  color: #888;
}
.otp-resend a {
  color: #d40511;
  text-decoration: none;
  font-weight: 600;
  cursor: pointer;
}
.otp-resend a:hover {
  text-decoration: underline;
}
.otp-resend a.disabled {
  color: #ccc;
  pointer-events: none;
}

/* Fade in animation */
.otp-container > * {
  opacity: 0;
  transform: translateY(10px);
  animation: otpFadeIn 0.5s ease forwards;
}
.otp-container > *:nth-child(1) { animation-delay: 0.05s; }
.otp-container > *:nth-child(2) { animation-delay: 0.15s; }
.otp-container > *:nth-child(3) { animation-delay: 0.25s; }
.otp-container > *:nth-child(4) { animation-delay: 0.3s; }
.otp-container > *:nth-child(5) { animation-delay: 0.35s; }
.otp-container > *:nth-child(6) { animation-delay: 0.4s; }
.otp-container > *:nth-child(7) { animation-delay: 0.5s; }
.otp-container > *:nth-child(8) { animation-delay: 0.6s; }
.otp-container > *:nth-child(9) { animation-delay: 0.7s; }
@keyframes otpFadeIn {
  to { opacity: 1; transform: translateY(0); }
}

