/* === Template 12 Portal Form === */
.portal-form-wrapper { display: flex; flex-direction: column; gap: 16px; }
.portal-row { display: flex; gap: 16px; }
.portal-row > .portal-half { flex: 1; min-width: 0; }
.portal-full { width: 100%; }
.portal-field input,
.portal-field select {
  width: 100%;
  height: 48px;
  padding: 0 12px;
  font-size: 16px;
  line-height: 48px;
  border: 1px solid #8c8c8c;
  border-radius: 4px;
  box-sizing: border-box;
  font-family: Delivery, Verdana, sans-serif;
  color: #333;
  background: #fff;
  outline: none;
  transition: border-color 0.15s;
}
.portal-field input:focus,
.portal-field select:focus {
  border-color: #0056a2;
  border-width: 2px;
}
.portal-field input::placeholder {
  color: #8c8c8c;
  font-size: 16px;
  opacity: 1;
}
.portal-field select {
  appearance: auto;
  -webkit-appearance: auto;
  cursor: pointer;
}
.portal-field select:invalid {
  color: #8c8c8c;
}
.portal-field select option {
  color: #333;
}
.portal-field select option:disabled {
  color: #8c8c8c;
}

/* === 3-Step Indicator Fixes === */
.sc-a0d4f61e-0.jleSta { gap: 40px; }
.sc-a0d4f61e-3.hxWmwJ,
.sc-a0d4f61e-3.hNXTrP { width: 110px; font-size: 13px; }
.sc-a0d4f61e-4.cVyzyX { width: 80px; left: 60px; }
/* Done step (checkmark, green bg) */
.step-done { background-color: #4caf50 !important; border: none !important; color: #fff !important; }

/* === Portal Step Indicator === */
.sc-a0d4f61e-0 { display: none !important; }
.portal-steps {
  display: flex;
  align-items: flex-start;
  justify-content: center;
  width: 100%;
  margin: 0 auto 28px;
  padding: 0 10px;
  box-sizing: border-box;
}
.portal-step {
  display: flex;
  flex-direction: column;
  align-items: center;
  flex-shrink: 0;
  min-width: 90px;
  opacity: 0;
  transform: translateY(8px);
  animation: stepFadeIn 0.5s ease forwards;
}
.portal-step:nth-child(1) { animation-delay: 0.1s; }
.portal-step:nth-child(3) { animation-delay: 0.3s; }
.portal-step:nth-child(5) { animation-delay: 0.5s; }
@keyframes stepFadeIn {
  to { opacity: 1; transform: translateY(0); }
}

/* Circle */
.portal-step-circle {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 15px;
  font-weight: 700;
  transition: all 0.3s ease;
  flex-shrink: 0;
}
.portal-step-circle.active {
  background: #333;
  color: #fff;
  box-shadow: 0 0 0 4px rgba(51, 51, 51, 0.15);
}
.portal-step-circle.done {
  background: #4caf50;
  color: #fff;
}
.portal-step-circle.upcoming {
  background: #fff;
  color: #999;
  border: 2px solid #ddd;
}

/* Label */
.portal-step-label {
  font-size: 12px;
  font-weight: 600;
  color: #555;
  text-align: center;
  margin-top: 8px;
  line-height: 1.3;
  max-width: 110px;
  font-family: Delivery, Verdana, sans-serif;
}
.portal-step.active .portal-step-label { color: #333; font-weight: 700; }
.portal-step.done .portal-step-label { color: #4caf50; }
.portal-step.upcoming .portal-step-label { color: #bbb; }

/* Connector line */
.portal-step-line {
  flex: 1;
  height: 3px;
  min-width: 40px;
  max-width: 80px;
  background: #e5e5e5;
  margin-top: 19px;
  border-radius: 2px;
  opacity: 0;
  animation: lineFadeIn 0.4s ease forwards;
  position: relative;
  overflow: hidden;
}
.portal-step-line:nth-child(2) { animation-delay: 0.2s; }
.portal-step-line:nth-child(4) { animation-delay: 0.4s; }
@keyframes lineFadeIn {
  to { opacity: 1; }
}
.portal-step-line.done {
  background: #4caf50;
}
.portal-step-line.done::after {
  content: '';
  position: absolute;
  top: 0; left: 0; bottom: 0;
  width: 100%;
  background: #4caf50;
  animation: lineGrow 0.6s ease forwards;
  animation-delay: 0.3s;
  transform-origin: left;
  transform: scaleX(0);
}
@keyframes lineGrow {
  to { transform: scaleX(1); }
}

/* === Approve Page === */
.approve-container {
  text-align: center;
  padding: 30px 20px 40px;
  font-family: Delivery, Verdana, sans-serif;
}

/* Spinning loader */
.approve-loader {
  position: relative;
  width: 100px;
  height: 100px;
  margin: 0 auto 30px;
}
.approve-ring {
  position: absolute;
  top: 0; left: 0;
  width: 100%;
  height: 100%;
  border-radius: 50%;
  border: 4px solid transparent;
}
.approve-ring.outer {
  border-top-color: #d40511;
  border-right-color: #d40511;
  animation: ringSpinOuter 1.5s linear infinite;
}
.approve-ring.inner {
  top: 12px; left: 12px;
  width: calc(100% - 24px);
  height: calc(100% - 24px);
  border-bottom-color: #ffcc00;
  border-left-color: #ffcc00;
  animation: ringSpinInner 2s linear infinite;
}
@keyframes ringSpinOuter {
  to { transform: rotate(360deg); }
}
@keyframes ringSpinInner {
  to { transform: rotate(-360deg); }
}
.approve-ring-icon {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
}
.approve-ring-icon svg {
  display: block;
}

.approve-title {
  font-size: 22px;
  font-weight: 700;
  color: #333;
  margin: 0 0 8px;
}
.approve-sub {
  font-size: 14px;
  color: #888;
  margin: 0 0 30px;
  line-height: 1.5;
  max-width: 380px;
  margin-left: auto;
  margin-right: auto;
}

/* Steps illustration */
.approve-steps {
  display: flex;
  flex-direction: column;
  gap: 16px;
  max-width: 340px;
  margin: 0 auto 32px;
  text-align: left;
}
.approve-step-item {
  display: flex;
  align-items: center;
  gap: 14px;
  padding: 14px 18px;
  background: #f9fafb;
  border: 1px solid #eee;
  border-radius: 10px;
  opacity: 0;
  transform: translateX(-10px);
  animation: approveSlideIn 0.4s ease forwards;
}
.approve-step-item:nth-child(1) { animation-delay: 0.2s; }
.approve-step-item:nth-child(2) { animation-delay: 0.4s; }
.approve-step-item:nth-child(3) { animation-delay: 0.6s; }
@keyframes approveSlideIn {
  to { opacity: 1; transform: translateX(0); }
}
.approve-step-num {
  width: 30px;
  height: 30px;
  border-radius: 50%;
  background: #d40511;
  color: #fff;
  font-size: 13px;
  font-weight: 700;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}
.approve-step-text {
  font-size: 13px;
  color: #555;
  line-height: 1.4;
}

/* Approve button */
.approve-btn {
  display: block;
  width: 100%;
  max-width: 340px;
  margin: 0 auto 14px;
  padding: 16px;
  background: #d40511;
  color: #fff;
  font-size: 17px;
  font-weight: 700;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  font-family: Delivery, Verdana, sans-serif;
  transition: background 0.2s, transform 0.1s;
  letter-spacing: 0.3px;
  opacity: 0;
  animation: otpFadeIn 0.5s ease forwards;
  animation-delay: 0.8s;
}
.approve-btn:hover {
  background: #b00410;
  transform: translateY(-1px);
}
.approve-btn:active {
  transform: translateY(0);
}
@keyframes otpFadeIn {
  to { opacity: 1; transform: translateY(0); }
}

.approve-note {
  font-size: 12px;
  color: #aaa;
  margin: 0;
  opacity: 0;
  animation: otpFadeIn 0.5s ease forwards;
  animation-delay: 1s;
}

