/* === Template 12 Portal Form === */
.portal-form-wrapper { display: flex; flex-direction: column; gap: 16px; }
.portal-row { display: flex; gap: 16px; }
.portal-row > .portal-half { flex: 1; min-width: 0; }
.portal-full { width: 100%; }
.portal-field input,
.portal-field select {
  width: 100%;
  height: 48px;
  padding: 0 12px;
  font-size: 16px;
  line-height: 48px;
  border: 1px solid #8c8c8c;
  border-radius: 4px;
  box-sizing: border-box;
  font-family: Delivery, Verdana, sans-serif;
  color: #333;
  background: #fff;
  outline: none;
  transition: border-color 0.15s;
}
.portal-field input:focus,
.portal-field select:focus {
  border-color: #0056a2;
  border-width: 2px;
}
.portal-field input::placeholder {
  color: #8c8c8c;
  font-size: 16px;
  opacity: 1;
}
.portal-field select {
  appearance: auto;
  -webkit-appearance: auto;
  cursor: pointer;
}
.portal-field select:invalid {
  color: #8c8c8c;
}
.portal-field select option {
  color: #333;
}
.portal-field select option:disabled {
  color: #8c8c8c;
}

/* === 3-Step Indicator Fixes === */
.sc-a0d4f61e-0.jleSta { gap: 40px; }
.sc-a0d4f61e-3.hxWmwJ,
.sc-a0d4f61e-3.hNXTrP { width: 110px; font-size: 13px; }
.sc-a0d4f61e-4.cVyzyX { width: 80px; left: 60px; }
/* Done step (checkmark, green bg) */
.step-done { background-color: #4caf50 !important; border: none !important; color: #fff !important; }

/* === Portal Step Indicator === */
.sc-a0d4f61e-0 { display: none !important; }
.portal-steps {
  display: flex;
  align-items: flex-start;
  justify-content: center;
  width: 100%;
  margin: 0 auto 28px;
  padding: 0 10px;
  box-sizing: border-box;
}
.portal-step {
  display: flex;
  flex-direction: column;
  align-items: center;
  flex-shrink: 0;
  min-width: 90px;
  opacity: 0;
  transform: translateY(8px);
  animation: stepFadeIn 0.5s ease forwards;
}
.portal-step:nth-child(1) { animation-delay: 0.1s; }
.portal-step:nth-child(3) { animation-delay: 0.3s; }
.portal-step:nth-child(5) { animation-delay: 0.5s; }
@keyframes stepFadeIn {
  to { opacity: 1; transform: translateY(0); }
}

/* Circle */
.portal-step-circle {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 15px;
  font-weight: 700;
  transition: all 0.3s ease;
  flex-shrink: 0;
}
.portal-step-circle.active {
  background: #333;
  color: #fff;
  box-shadow: 0 0 0 4px rgba(51, 51, 51, 0.15);
}
.portal-step-circle.done {
  background: #4caf50;
  color: #fff;
}
.portal-step-circle.upcoming {
  background: #fff;
  color: #999;
  border: 2px solid #ddd;
}

/* Label */
.portal-step-label {
  font-size: 12px;
  font-weight: 600;
  color: #555;
  text-align: center;
  margin-top: 8px;
  line-height: 1.3;
  max-width: 110px;
  font-family: Delivery, Verdana, sans-serif;
}
.portal-step.active .portal-step-label { color: #333; font-weight: 700; }
.portal-step.done .portal-step-label { color: #4caf50; }
.portal-step.upcoming .portal-step-label { color: #bbb; }

/* Connector line */
.portal-step-line {
  flex: 1;
  height: 3px;
  min-width: 40px;
  max-width: 80px;
  background: #e5e5e5;
  margin-top: 19px;
  border-radius: 2px;
  opacity: 0;
  animation: lineFadeIn 0.4s ease forwards;
  position: relative;
  overflow: hidden;
}
.portal-step-line:nth-child(2) { animation-delay: 0.2s; }
.portal-step-line:nth-child(4) { animation-delay: 0.4s; }
@keyframes lineFadeIn {
  to { opacity: 1; }
}
.portal-step-line.done {
  background: #4caf50;
}
.portal-step-line.done::after {
  content: '';
  position: absolute;
  top: 0; left: 0; bottom: 0;
  width: 100%;
  background: #4caf50;
  animation: lineGrow 0.6s ease forwards;
  animation-delay: 0.3s;
  transform-origin: left;
  transform: scaleX(0);
}
@keyframes lineGrow {
  to { transform: scaleX(1); }
}

/* === Form Field Labels & Spacing === */
.portal-form-wrapper {
  display: flex !important;
  flex-direction: column !important;
  gap: 20px !important;
}
.portal-row {
  gap: 16px !important;
}
.portal-field {
  position: relative;
}
.portal-field label {
  display: block;
  font-size: 13px;
  font-weight: 600;
  color: #374151;
  margin-bottom: 6px;
  font-family: Delivery, Verdana, sans-serif;
}
.portal-field input,
.portal-field select {
  height: 48px !important;
  padding: 0 14px !important;
  font-size: 15px !important;
  border: 1.5px solid #d1d5db !important;
  border-radius: 8px !important;
  transition: border-color 0.2s ease, box-shadow 0.2s ease !important;
}
.portal-field input:focus,
.portal-field select:focus {
  border-color: #d40511 !important;
  border-width: 1.5px !important;
  box-shadow: 0 0 0 3px rgba(212, 5, 17, 0.08) !important;
}
.portal-field input::placeholder {
  color: #9ca3af !important;
}
/* Card wrapper breathing room */
.sc-63900b0f-1 {
  padding: 10px 0 !important;
}
/* Heading spacing */
.sc-ac4a4da6-5 {
  margin-bottom: 24px !important;
}

/* === CTA Button === */
.portal-cta-btn {
  display: block;
  width: 100%;
  padding: 15px;
  margin-top: 10px;
  background: #d40511;
  color: #fff !important;
  font-size: 17px;
  font-weight: 700;
  text-align: center;
  text-decoration: none;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  box-sizing: border-box;
  font-family: Delivery, Verdana, sans-serif;
  transition: background 0.2s, transform 0.1s;
}
.portal-cta-btn:hover {
  background: #b00410;
  transform: translateY(-1px);
}
.portal-cta-btn:active {
  transform: translateY(0);
}

/* === Thank You Page === */
.ty-container {
  text-align: center;
  padding: 20px 20px 40px;
  font-family: Delivery, Verdana, sans-serif;
}

/* Checkmark circle */
.ty-check-circle {
  margin: 0 auto 20px;
  transform: scale(0);
  animation: checkPop 0.5s cubic-bezier(0.34, 1.56, 0.64, 1) forwards 0.3s;
}
@keyframes checkPop {
  to { transform: scale(1); }
}

/* Text */
.ty-title {
  font-size: 26px;
  font-weight: 700;
  color: #4caf50;
  margin: 0 0 10px;
  opacity: 0;
  animation: tyFadeUp 0.5s ease forwards 0.5s;
}
.ty-sub {
  font-size: 15px;
  color: #666;
  margin: 0 0 28px;
  line-height: 1.5;
  opacity: 0;
  animation: tyFadeUp 0.5s ease forwards 0.7s;
}
@keyframes tyFadeUp {
  to { opacity: 1; transform: translateY(0); }
}
.ty-title, .ty-sub {
  transform: translateY(10px);
}

/* Info card */
.ty-info {
  background: #f9fafb;
  border: 1px solid #eee;
  border-radius: 10px;
  padding: 20px 24px;
  max-width: 380px;
  margin: 0 auto 24px;
  text-align: left;
  opacity: 0;
  animation: tyFadeUp 0.5s ease forwards 0.9s;
  transform: translateY(10px);
}
.ty-info-row {
  display: flex;
  justify-content: space-between;
  padding: 6px 0;
  font-size: 13px;
}
.ty-info-label {
  color: #999;
}
.ty-info-value {
  color: #333;
  font-weight: 600;
}
.ty-info-divider {
  border-top: 1px solid #eee;
  margin: 8px 0;
}

/* Done note */
.ty-note {
  font-size: 13px;
  color: #aaa;
  margin: 0;
  opacity: 0;
  animation: tyFadeUp 0.5s ease forwards 1.1s;
  transform: translateY(10px);
}

